import React, { createContext, useState, useContext, useEffect } from 'react';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [session, setSession] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const savedSession = localStorage.getItem('user-session');
        if (savedSession) {
            try {
                const parsed = JSON.parse(savedSession);
                console.log("AUTH_DEBUG: Sesión recuperada:", parsed);
                setSession(parsed);
            } catch (e) {
                localStorage.removeItem('user-session');
            }
        }
        setLoading(false);
    }, []);

    const login = (userData) => {
        setSession(userData);
        localStorage.setItem('user-session', JSON.stringify(userData));
    };

    const logout = () => {
        setSession(null);
        localStorage.removeItem('user-session');
        localStorage.removeItem('active-cart');
        window.location.href = '/login';
    };

    // Buscamos el objeto usuario sin importar la profundidad
    const currentUser = session?.user ? session.user : session;

    return (
        <AuthContext.Provider value={{ 
            user: currentUser, 
            token: session?.token, 
            isAuthenticated: !!session,
            login, 
            logout,
            loading 
        }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);
